use std::collections::HashMap;

struct AppConfig {
    settings: HashMap<String, String>,
}

impl AppConfig {
    fn new() -> Self {
        AppConfig { settings: HashMap::new() }
    }

    fn load_setting(&mut self, key: &str, value: impl AsRef<[u8]>) -> Result<(), String> {
        let raw_value = std::str::from_utf8(value.as_ref()).map_err(|_| "Invalid UTF-8 bytes provided".to_string())?;
        self.settings.insert(key.to_owned(), raw_value.to_owned());
        Ok(())
    }

    fn print_setting(&self, key: &str) {
        match self.settings.get(key) {
            Some(value) => println!("Loaded setting for '{}': {}", key, value),
            None => println!("Setting '{}' not found.", key),
        }
    }
}

fn main() {
    let mut config = AppConfig::new();

    // Simulate loading a temporary/request-scoped setting (using &str concept)
    config.load_setting("api_key", "temp_secret_123" ).unwrap();

    // Simulate loading a persistent application setting (requires ownership)
    let app_name = String::from("WebAppServer");
    config.load_setting(&app_name, b"production_mode_flag").unwrap();

    // Use the loaded settings
    config.print_setting("api_key");
    config.print_setting("webappserver");
}

use std::collections::HashMap;

struct Record {
    key: String,
