fn process_csv(data_line: &str) -> HashMap<String, Vec<&str>> {
    let mut result = HashMap::new();
    let fields: Vec<&str> = data_line.split(',').collect();
    for (i, field) in fields.iter().enumerate() {
        let key = format!("column_{}", i);
        result.entry(key).or_insert_with(Vec::new).push(*field);
    }
    result
}

fn main() {
    let data = "user_id,first_name,last_name";
    println!("Processing header: {}", data);
    let processed_header = process_csv(data);
    for (key, values) in &processed_header { 
        println!("{}: {:?}", key, values);
    }

    let data_row = "1024,Alice,Smith";
    println!("nProcessing row: {}", data_row);
    let processed_row = process_csv(data_row);
    for (key, values) in &processed_row { 
        println!("{}: {:?}", key, values); 
    }
}

use std::io::{self, BufRead};
fn main() -> io::Result<()> {
    let input_data = "user_id:1024nproduct_sku:XYZ789nsession_token:abcde";
    let reader = io::BufReader::new(std::io::Cursor::new(input_data.as_bytes()));

    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => continue,
        };

        if let Some((key, value)) = process_log_line(&line) {
            println!("Processed Key: {}", key);
            println!("Processed Value: {}", value);
        } else {
            println!("Could not parse line: {}", line);
        }
    }
    Ok(())
}

fn process_log_line(line: &str) -> Option<(&str, &str)> {
    let parts: Vec<&str> = line.split(':').collect();
    if parts.len() == 2 {
        let key = parts[0].trim();
        let value = parts[1].trim();
        Some((key, value))
    } else {
        None
    }
}

use std::fs;
use std::io::{self, Write};

struct AppConfig {
    server_name: String,
    port: u16,
}

impl AppConfig {
    fn load_from_file(path: &str) -> io::Result<AppConfig> {
        let content = fs::read_to_string(path)?;
        let mut lines = content.lines();

        let server_name_line = lines.next().unwrap_or(&"default_server");
        let server_name: String = server_name_line.trim().split(':').nth(0).unwrap_or("default_server").to_string();

        let port_line = lines.next().unwrap_or(&"8080");
        let port: u16 = port_line.trim().split(':').nth(1).map(|s| s.parse::<u16>().unwrap_or(8080)).unwrap_or(8080);

        Ok(AppConfig {
            server_name,
            port,
        })
    }

    fn print_status(&self) -> io::Result<()> {
        write!(io::stdout(), "---------------------------n")?;
        write!(io::stdout(), "Config Loaded: Server = {}, Port = {}n", self.server_name, self.port)?;
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let temp_config_path = "settings.conf";
    let initial_content = "server_name: MyAppServernport: 9000";
    fs::write(temp_config_path, initial_content)?;

    let config1 = AppConfig::load_from_file(temp_config_path)?;
    config1.print_status()?;

    let new_content = "server_name: NewAppServernport: 80";
    fs::write(temp_config_path, new_content)?;

    let config2 = AppConfig::load_from_file(temp_config_path)?;
    config2.print_status()?;

    fs::remove_file(temp_config_path)?;
    Ok(())
}

use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct PlayerNameProcessor {
    processed_names: Vec<String>,
}

impl PlayerNameProcessor {
    fn new() -> Self {
        PlayerNameProcessor { processed_names: Vec::new() }
    }

    fn read_and_process_names(&mut self, filepath: &str) -> io::Result<()> {
        let file = File::open(filepath)?;
        let reader = BufReader::new(file);

        for line in reader.lines() {
            let line_str = line?;
            if line_str.trim().is_empty() {
                continue;
            }

            let name: String = line_str.to_owned();
            println!("Successfully read and processing owned name: {}", name);

            self.process_name_slice(&name);
        }
        Ok(())
    }

    fn process_name_slice(&mut self, name_slice: &str) {
        let upper_case = name_slice.to_uppercase();
        println!("  Processed slice result: {}", upper_case);
        self.processed_names.push(upper_case);
    }
}

fn main() -> io::Result<()> {
    use std::env;
    let args: Vec<String> = env::args().collect();

    if args.len() != 2 {
        eprintln!("Usage: <path_to_name_file>");
        return Ok(());
    }

    let file_path = &args[1];
    let mut processor = PlayerNameProcessor::new();

    if let Err(e) = processor.read_and_process_names(file_path) {
        eprintln!("An error occurred: {}", e);
    }

    println!("nFinished processing. Total unique names recorded: {}", processor.processed_names.len());
    Ok(())
}
